import{_ as t,c as n,o as e,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"计划评审: 可视化评审 AI 计划 | Plannotator","description":"学习 Plannotator 计划评审功能。使用可视化界面评审 AI 生成的计划，添加注释批准或拒绝，掌握 Approve 和 Request Changes 的区别。","frontmatter":{"title":"计划评审: 可视化评审 AI 计划 | Plannotator","subtitle":"计划评审基础：可视化评审 AI 计划","description":"学习 Plannotator 计划评审功能。使用可视化界面评审 AI 生成的计划，添加注释批准或拒绝，掌握 Approve 和 Request Changes 的区别。","sidebarTitle":"5 分钟学会评审计划","tags":["计划评审","可视化评审","注释","批准","拒绝","Claude Code","OpenCode"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"zh/backnotprop/plannotator/platforms/plan-review-basics/index.md","filePath":"zh/backnotprop/plannotator/platforms/plan-review-basics/index.md"}'),o={name:"zh/backnotprop/plannotator/platforms/plan-review-basics/index.md"};function l(p,a,i,r,d,c){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="计划评审基础-可视化评审-ai-计划" tabindex="-1">计划评审基础：可视化评审 AI 计划 <a class="header-anchor" href="#计划评审基础-可视化评审-ai-计划" aria-label="Permalink to &quot;计划评审基础：可视化评审 AI 计划&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>✅ 使用 Plannotator 可视化界面评审 AI 生成的计划</li><li>✅ 选中计划文本，添加不同类型的注释（删除、替换、评论）</li><li>✅ 批准计划，让 AI 继续实施</li><li>✅ 拒绝计划，将注释作为反馈发送给 AI</li><li>✅ 理解注释类型的使用场景和区别</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p><strong>问题 1</strong>：AI 生成的实施计划在终端里阅读，文字量大、结构不清晰，评审起来很累。</p><p><strong>问题 2</strong>：想给 AI 反馈时，只能用文字描述&quot;删除第3段&quot;、&quot;修改这个函数&quot;，沟通成本高，AI 也可能理解错误。</p><p><strong>问题 3</strong>：计划中有些地方不需要修改，有些地方需要替换，有些地方需要评论，但没有工具帮你结构化这些反馈。</p><p><strong>问题 4</strong>：不知道如何让 AI 知道你批准了计划，还是需要修改。</p><p><strong>Plannotator 能帮你</strong>：</p><ul><li>可视化 UI 替代终端阅读，结构清晰</li><li>选中文本即可添加注释（删除、替换、评论），精确反馈</li><li>注释自动转换为结构化数据，AI 准确理解你的意图</li><li>一键批准或拒绝，AI 立即响应</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p><strong>使用场景</strong>：</p><ul><li>AI Agent 完成计划并调用 <code>ExitPlanMode</code>（Claude Code）</li><li>AI Agent 调用 <code>submit_plan</code> 工具（OpenCode）</li><li>需要评审 AI 生成的实施计划</li><li>需要精确反馈计划的修改意见</li></ul><p><strong>不适用场景</strong>：</p><ul><li>直接让 AI 实施代码（跳过计划评审）</li><li>已经批准计划，需要评审实际代码变更（使用代码评审功能）</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><p><strong>前置条件</strong>：</p><ul><li>✅ 已安装 Plannotator CLI（详见 <a href="./../start/getting-started/">快速开始</a>）</li><li>✅ 已配置 Claude Code 或 OpenCode 插件（详见对应安装指南）</li><li>✅ AI Agent 支持计划评审（Claude Code 2.1.7+，或 OpenCode）</li></ul><p><strong>触发方式</strong>：</p><ul><li><strong>Claude Code</strong>：AI 完成 plan 后自动调用 <code>ExitPlanMode</code>，Plannotator 自动启动</li><li><strong>OpenCode</strong>：AI 调用 <code>submit_plan</code> 工具，Plannotator 自动启动</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="计划评审是什么" tabindex="-1">计划评审是什么 <a class="header-anchor" href="#计划评审是什么" aria-label="Permalink to &quot;计划评审是什么&quot;">​</a></h3><p><strong>计划评审</strong>是 Plannotator 的核心功能，用于可视化评审 AI 生成的实施计划。</p><div class="info custom-block"><p class="custom-block-title">为什么需要计划评审？</p><p>AI 生成计划后，通常会问&quot;这个计划可以吗？&quot;或&quot;是否开始实施？&quot;。如果没有可视化工具，你只能在终端里阅读纯文本计划，然后回复&quot;可以&quot;、&quot;不行，修改XX&quot;等模糊反馈。Plannotator 让你用可视化界面查看计划，精确选中需要修改的部分，添加结构化注释，AI 更容易理解你的意图。</p></div><h3 id="工作流程" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程" aria-label="Permalink to &quot;工作流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (生成计划)    │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ ExitPlanMode / submit_plan</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ Plannotator UI  │  ← 浏览器自动打开</span></span>
<span class="line"><span>│                 │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 计划内容   │  │</span></span>
<span class="line"><span>│ │ (Markdown) │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       │ 选中文本</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 添加注释   │  │</span></span>
<span class="line"><span>│ │ Delete/    │  │</span></span>
<span class="line"><span>│ │ Replace/   │  │</span></span>
<span class="line"><span>│ │ Comment    │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 决策      │  │</span></span>
<span class="line"><span>│ │ Approve/  │  │</span></span>
<span class="line"><span>│ │ Request   │  │</span></span>
<span class="line"><span>│ │ Changes   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;allow&quot;} 或</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (继续实施)    │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h3 id="注释类型" tabindex="-1">注释类型 <a class="header-anchor" href="#注释类型" aria-label="Permalink to &quot;注释类型&quot;">​</a></h3><p>Plannotator 支持四种注释类型，每种都有不同的用途：</p><table tabindex="0"><thead><tr><th>注释类型</th><th>用途</th><th>AI 收到的反馈</th></tr></thead><tbody><tr><td><strong>Delete</strong></td><td>删除不需要的内容</td><td>&quot;删除：[选中的文本]&quot;</td></tr><tr><td><strong>Replace</strong></td><td>替换为更好的内容</td><td>&quot;替换：[选中的文本] 为 [你输入的文本]&quot;</td></tr><tr><td><strong>Comment</strong></td><td>评论某段内容，不要求修改</td><td>&quot;评论：[选中的文本]。说明：[你输入的评论]&quot;</td></tr><tr><td><strong>Global Comment</strong></td><td>全局评论，不关联具体文本</td><td>&quot;全局评论：[你输入的评论]&quot;</td></tr></tbody></table><h3 id="approve-vs-request-changes" tabindex="-1">Approve vs Request Changes <a class="header-anchor" href="#approve-vs-request-changes" aria-label="Permalink to &quot;Approve vs Request Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>决策类型</th><th>操作</th><th>AI 收到的反馈</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>点击 Approve 按钮</td><td><code>{&quot;behavior&quot;: &quot;allow&quot;}</code></td><td>计划没问题，直接批准</td></tr><tr><td><strong>Request Changes</strong></td><td>点击 Request Changes 按钮</td><td><code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></td><td>有需要修改的地方</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Claude Code 和 OpenCode 的差异</p><ul><li><strong>Claude Code</strong>：Approve 时不会发送注释（注释会被忽略）</li><li><strong>OpenCode</strong>：Approve 时可以发送注释作为备注（可选）</li></ul><p><strong>拒绝计划时</strong>：无论哪个平台，注释都会发送给 AI</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-触发计划评审" tabindex="-1">第 1 步：触发计划评审 <a class="header-anchor" href="#第-1-步-触发计划评审" aria-label="Permalink to &quot;第 1 步：触发计划评审&quot;">​</a></h3><p><strong>Claude Code 示例</strong>：</p><p>在 Claude Code 中与 AI 对话，让 AI 生成一个实施计划：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：帮我写一个用户认证模块的实施计划</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude：好的，这是实施计划：</span></span>
<span class="line"><span>1. 创建用户模型</span></span>
<span class="line"><span>2. 实现注册 API</span></span>
<span class="line"><span>3. 实现登录 API</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>（AI 调用 ExitPlanMode）</span></span></code></pre></div><p><strong>OpenCode 示例</strong>：</p><p>在 OpenCode 中，AI 会自动调用 <code>submit_plan</code> 工具。</p><p><strong>你应该看到</strong>：</p><ol><li>浏览器自动打开 Plannotator UI</li><li>显示 AI 生成的计划内容（Markdown 格式）</li><li>页面底部有&quot;Approve&quot;和&quot;Request Changes&quot;按钮</li></ol><h3 id="第-2-步-浏览计划内容" tabindex="-1">第 2 步：浏览计划内容 <a class="header-anchor" href="#第-2-步-浏览计划内容" aria-label="Permalink to &quot;第 2 步：浏览计划内容&quot;">​</a></h3><p>在浏览器中查看计划：</p><ul><li>计划以 Markdown 格式渲染，包括标题、段落、列表、代码块</li><li>可以滚动查看整个计划</li><li>支持亮/暗模式切换（点击右上角的主题切换按钮）</li></ul><h3 id="第-3-步-选中计划文本-添加注释" tabindex="-1">第 3 步：选中计划文本，添加注释 <a class="header-anchor" href="#第-3-步-选中计划文本-添加注释" aria-label="Permalink to &quot;第 3 步：选中计划文本，添加注释&quot;">​</a></h3><p><strong>添加 Delete 注释</strong>：</p><ol><li>用鼠标选中计划中需要删除的文本</li><li>在弹出的工具栏中点击 <strong>Delete</strong> 按钮</li><li>文本会被标记为删除样式（红色删除线）</li></ol><p><strong>添加 Replace 注释</strong>：</p><ol><li>用鼠标选中计划中需要替换的文本</li><li>在弹出的工具栏中点击 <strong>Replace</strong> 按钮</li><li>在弹出的输入框中输入替换后的内容</li><li>按回车或点击确认</li><li>原文本会被标记为替换样式（黄色背景），并在下方显示替换内容</li></ol><p><strong>添加 Comment 注释</strong>：</p><ol><li>用鼠标选中计划中需要评论的文本</li><li>在弹出的工具栏中点击 <strong>Comment</strong> 按钮</li><li>在弹出的输入框中输入评论内容</li><li>按回车或点击确认</li><li>文本会被标记为评论样式（蓝色高亮），并在侧边栏显示评论</li></ol><p><strong>添加 Global Comment</strong>：</p><ol><li>点击页面右上角的 <strong>Add Global Comment</strong> 按钮</li><li>在弹出的输入框中输入全局评论内容</li><li>按回车或点击确认</li><li>评论会显示在侧边栏的&quot;Global Comments&quot;部分</li></ol><p><strong>你应该看到</strong>：</p><ul><li>选中文本后，会立即弹出工具栏（Delete、Replace、Comment）</li><li>添加注释后，文本会显示相应的样式（删除线、背景色、高亮）</li><li>侧边栏会显示所有注释列表，可以点击跳转到对应位置</li><li>可以点击注释旁的 <strong>删除</strong> 按钮移除注释</li></ul><h3 id="第-4-步-批准计划" tabindex="-1">第 4 步：批准计划 <a class="header-anchor" href="#第-4-步-批准计划" aria-label="Permalink to &quot;第 4 步：批准计划&quot;">​</a></h3><p><strong>如果计划没有问题</strong>：</p><p>点击页面底部的 <strong>Approve</strong> 按钮。</p><p><strong>你应该看到</strong>：</p><ul><li>浏览器自动关闭（1.5 秒延迟）</li><li>Claude Code/OpenCode 终端中显示计划已批准</li><li>AI 继续实施计划</li></ul><div class="info custom-block"><p class="custom-block-title">Approve 的行为</p><ul><li><strong>Claude Code</strong>：只发送 <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>，注释被忽略</li><li><strong>OpenCode</strong>：发送 <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>，注释可以作为备注发送（可选）</li></ul></div><h3 id="第-5-步-拒绝计划-request-changes" tabindex="-1">第 5 步：拒绝计划（Request Changes） <a class="header-anchor" href="#第-5-步-拒绝计划-request-changes" aria-label="Permalink to &quot;第 5 步：拒绝计划（Request Changes）&quot;">​</a></h3><p><strong>如果计划需要修改</strong>：</p><ol><li>添加必要的注释（Delete、Replace、Comment）</li><li>点击页面底部的 <strong>Request Changes</strong> 按钮</li><li>浏览器会显示确认对话框</li></ol><p><strong>你应该看到</strong>：</p><ul><li>确认对话框显示&quot;Send X annotations to AI?&quot;</li><li>点击确认后，浏览器自动关闭</li><li>Claude Code/OpenCode 终端中显示反馈内容</li><li>AI 会根据反馈修改计划</li></ul><div class="tip custom-block"><p class="custom-block-title">Request Changes 的行为</p><ul><li><strong>Claude Code</strong> 和 <strong>OpenCode</strong>：都会发送 <code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></li><li>注释会被转换为结构化的 Markdown 文本</li><li>AI 会根据注释修改计划并再次调用 ExitPlanMode/submit_plan</li></ul></div><h3 id="第-6-步-查看反馈内容-可选" tabindex="-1">第 6 步：查看反馈内容（可选） <a class="header-anchor" href="#第-6-步-查看反馈内容-可选" aria-label="Permalink to &quot;第 6 步：查看反馈内容（可选）&quot;">​</a></h3><p>如果你想查看 Plannotator 发送给 AI 的反馈内容，可以在终端中查看：</p><p><strong>Claude Code</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan rejected by user</span></span>
<span class="line"><span>Please modify the plan based on the following feedback:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[结构化的注释内容]</span></span></code></pre></div><p><strong>OpenCode</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;feedback&gt;</span></span>
<span class="line"><span>[结构化的注释内容]</span></span>
<span class="line"><span>&lt;/feedback&gt;</span></span></code></pre></div><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>完成以上步骤后，你应该能够：</p><ul><li>[ ] 在 AI 触发计划评审后，浏览器自动打开 Plannotator UI</li><li>[ ] 选中计划文本，添加 Delete、Replace、Comment 注释</li><li>[ ] 添加 Global Comment</li><li>[ ] 在侧边栏查看所有注释，并跳转到对应位置</li><li>[ ] 点击 Approve，浏览器关闭，AI 继续实施</li><li>[ ] 点击 Request Changes，浏览器关闭，AI 修改计划</li></ul><p><strong>如果某一步失败</strong>，详见：</p><ul><li><a href="./../../faq/common-problems/">常见问题</a></li><li><a href="./../../start/installation-claude-code/">Claude Code 安装指南</a></li><li><a href="./../../start/installation-opencode/">OpenCode 安装指南</a></li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><p><strong>常见错误 1</strong>：选中文本后，工具栏没有弹出</p><p><strong>原因</strong>：可能是因为选中的是代码块中的文本，或者选中的文本跨多个元素。</p><p><strong>解决</strong>：</p><ul><li>尽量选中单个段落或列表项中的文本</li><li>对于代码块，可以使用 Comment 注释，不要跨多行选中</li></ul><p><strong>常见错误 2</strong>：添加 Replace 注释后，替换内容没有显示</p><p><strong>原因</strong>：替换内容输入框可能没有正确提交。</p><p><strong>解决</strong>：</p><ul><li>输入替换内容后，按回车键或点击确认按钮</li><li>检查侧边栏中是否显示了替换内容</li></ul><p><strong>常见错误 3</strong>：点击 Approve 或 Request Changes 后，浏览器没有关闭</p><p><strong>原因</strong>：可能是服务器错误或网络问题。</p><p><strong>解决</strong>：</p><ul><li>检查终端中是否有错误信息</li><li>手动关闭浏览器</li><li>如果问题持续，详见 <a href="./../../faq/troubleshooting/">故障排查</a></li></ul><p><strong>常见错误 4</strong>：AI 收到反馈后，没有按照注释修改</p><p><strong>原因</strong>：AI 可能没有正确理解注释的意图。</p><p><strong>解决</strong>：</p><ul><li>尝试使用更明确的注释（Replace 比 Comment 更明确）</li><li>使用 Comment 添加详细说明</li><li>如果问题持续，可以再次拒绝计划，并调整注释内容</li></ul><p><strong>常见错误 5</strong>：添加多个 Delete 注释后，AI 只删除了部分内容</p><p><strong>原因</strong>：多个 Delete 注释之间可能有重叠或冲突。</p><p><strong>解决</strong>：</p><ul><li>确保每个 Delete 注释的文本范围不重叠</li><li>如果需要删除大段内容，可以选中整个段落一次性删除</li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>计划评审是 Plannotator 的核心功能，让你可以可视化评审 AI 生成的计划：</p><p><strong>核心操作</strong>：</p><ol><li><strong>触发</strong>：AI 调用 <code>ExitPlanMode</code> 或 <code>submit_plan</code>，浏览器自动打开 UI</li><li><strong>浏览</strong>：在可视化界面中查看计划内容（Markdown 格式）</li><li><strong>注释</strong>：选中文本，添加 Delete、Replace、Comment 或 Global Comment</li><li><strong>决策</strong>：点击 Approve（批准）或 Request Changes（拒绝）</li><li><strong>反馈</strong>：注释被转换为结构化数据，AI 根据反馈继续或修改计划</li></ol><p><strong>注释类型</strong>：</p><ul><li><strong>Delete</strong>：删除不需要的内容</li><li><strong>Replace</strong>：替换为更好的内容</li><li><strong>Comment</strong>：评论某段内容，不要求修改</li><li><strong>Global Comment</strong>：全局评论，不关联具体文本</li></ul><p><strong>决策类型</strong>：</p><ul><li><strong>Approve</strong>：计划没问题，直接批准（Claude Code 会忽略注释）</li><li><strong>Request Changes</strong>：有需要修改的地方，注释发送给 AI</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../plan-review-annotations/">添加计划注释</a></strong>。</p><p>你会学到：</p><ul><li>如何精确使用 Delete、Replace、Comment 注释</li><li>如何添加图像标注</li><li>如何编辑和删除注释</li><li>注释的最佳实践和常见场景</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>计划评审 UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>注释类型定义</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L70" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-70</td></tr><tr><td>计划评审服务器</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L91-L310" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>91-310</td></tr><tr><td>API: 获取计划内容</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L132-L134" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>132-134</td></tr><tr><td>API: 批准计划</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L201-L277" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>201-277</td></tr><tr><td>API: 拒绝计划</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L280-L309" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>280-309</td></tr><tr><td>Viewer 组件</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L1-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>1-100</td></tr><tr><td>AnnotationPanel 组件</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a></td><td>1-50</td></tr></tbody></table><p><strong>关键类型</strong>：</p><ul><li><code>AnnotationType</code>：注释类型枚举（DELETION、INSERTION、REPLACEMENT、COMMENT、GLOBAL_COMMENT）（<code>packages/ui/types.ts:1-7</code>）</li><li><code>Annotation</code>：注释接口（<code>packages/ui/types.ts:11-33</code>）</li><li><code>Block</code>：计划块接口（<code>packages/ui/types.ts:35-44</code>）</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>startPlannotatorServer()</code>：启动计划评审服务器（<code>packages/server/index.ts:91</code>）</li><li><code>parseMarkdownToBlocks()</code>：将 Markdown 解析为 Blocks（<code>packages/ui/utils/parser.ts</code>）</li></ul><p><strong>API 路由</strong>：</p><ul><li><code>GET /api/plan</code>：获取计划内容（<code>packages/server/index.ts:132</code>）</li><li><code>POST /api/approve</code>：批准计划（<code>packages/server/index.ts:201</code>）</li><li><code>POST /api/deny</code>：拒绝计划（<code>packages/server/index.ts:280</code>）</li></ul><p><strong>业务规则</strong>：</p><ul><li>Claude Code 批准时不发送注释（<code>apps/hook/server/index.ts:132</code>）</li><li>OpenCode 批准时可发送注释作为备注（<code>apps/opencode-plugin/index.ts:270</code>）</li><li>拒绝计划时注释总是发送（<code>apps/hook/server/index.ts:154</code>）</li></ul></details>`,112)])])}const h=t(o,[["render",l]]);export{g as __pageData,h as default};
